ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name ?percentage_of_population WHERE {
  ?language a :Language .
  ?language p:name ?name .
  ?language p:Percentage_of_population ?percentage_of_population .
} }
  component_2: { SELECT ?name ?number_of_speakers WHERE {
  ?language a :Language .
  ?language p:name ?name .
  ?language p:Number_of_speakers ?number_of_speakers .
} }
  full: { SELECT ?name ?number_of_speakers ?percentage_of_population WHERE {
  ?language a :Language .
  ?language p:name ?name .
  ?language p:Number_of_speakers ?number_of_speakers .
  ?language p:Percentage_of_population ?percentage_of_population .
} }
}
